export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private priorityRouter: PriorityRouter | null = null;

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Attach a priority router to enable priority-based routing.
   * When set, sendWithPriority() routes through the router instead
   * of always using the email channel.
   */
  setPriorityRouter(router: PriorityRouter): void {
    this.priorityRouter = router;
  }

  /**
   * Send a notification routed by priority.
   * Requires a priority router to be set via setPriorityRouter().
   */
  sendWithPriority(params: {
    priority: NotificationPriority;
    recipient: string;
    subject: string;
    body: string;
    event: OrderCreatedEvent | OrderStatusChangedEvent;
  }): void {
    if (!this.priorityRouter) {
      throw new Error('Priority router not configured. Call setPriorityRouter() first.');
    }

    this.priorityRouter.route({
      priority: params.priority,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      event: params.event,
    });
  }

