import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { PriorityRouter } from '../../src/services/priority-router.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import {
  SmsChannelService,
  resetSmsIdCounter,
} from '../../src/services/sms-channel.service.js';
import {
  WebhookChannelService,
  resetWebhookIdCounter,
} from '../../src/services/webhook-channel.service.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('PriorityRouter', () => {
  let eventBus: EventBus;
  let smsChannel: SmsChannelService;
  let emailChannel: NotificationService;
  let webhookChannel: WebhookChannelService;
  let router: PriorityRouter;

  const orderCreatedEvent: OrderCreatedEvent = {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [
        { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
      ],
      total: 20,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
  };

  const statusChangedEvent: OrderStatusChangedEvent = {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 20,
      status: 'confirmed',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date(),
  };

  beforeEach(() => {
    eventBus = new EventBus();
    statusChangeCallbacks.clear();
    smsChannel = new SmsChannelService(eventBus);
    emailChannel = new NotificationService(eventBus);
    webhookChannel = new WebhookChannelService(eventBus);
    router = new PriorityRouter(smsChannel, emailChannel, webhookChannel);
    resetSmsIdCounter();
    resetNotificationIdCounter();
    resetWebhookIdCounter();
  });

  describe('routing by priority', () => {
    it('should route urgent notifications to SMS channel', () => {
      router.route({
        priority: 'urgent',
        recipient: 'user-1',
        subject: 'Order Confirmed',
        body: 'Your order has been confirmed.',
        event: orderCreatedEvent,
      });

      expect(smsChannel.getMessageCount()).toBe(1);
      expect(emailChannel.getNotificationCount()).toBe(0);
      expect(webhookChannel.getDeliveryCount()).toBe(0);

      const messages = smsChannel.getMessages();
      expect(messages[0]?.to).toBe('user-1');
      expect(messages[0]?.body).toContain('[URGENT]');
      expect(messages[0]?.body).toContain('Order Confirmed');
    });

    it('should route normal notifications to email channel', () => {
      router.route({
        priority: 'normal',
        recipient: 'alice@example.com',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
        event: orderCreatedEvent,
      });

      expect(smsChannel.getMessageCount()).toBe(0);
      expect(emailChannel.getNotificationCount()).toBe(1);
      expect(webhookChannel.getDeliveryCount()).toBe(0);

      const notifications = emailChannel.getNotifications();
      expect(notifications[0]?.recipient).toBe('alice@example.com');
      expect(notifications[0]?.subject).toBe('Order Confirmation');
      expect(notifications[0]?.body).toBe('Your order has been placed.');
    });

    it('should route low-priority notifications to webhook channel', () => {
      webhookChannel.registerWebhookUrl('order:created', 'https://hooks.example.com/orders');

      router.route({
        priority: 'low',
        recipient: 'user-1',
        subject: 'Order Update',
        body: 'Minor update.',
        event: orderCreatedEvent,
      });

      expect(smsChannel.getMessageCount()).toBe(0);
      expect(emailChannel.getNotificationCount()).toBe(0);
      expect(webhookChannel.getDeliveryCount()).toBe(1);

      const deliveries = webhookChannel.getDeliveries();
      expect(deliveries[0]?.eventType).toBe('order:created');
      expect(deliveries[0]?.url).toBe('https://hooks.example.com/orders');
    });
  });

  describe('routing log', () => {
    it('should log routing decisions', () => {
      router.route({
        priority: 'urgent',
        recipient: 'user-1',
        subject: 'Urgent',
        body: 'Urgent notification.',
        event: statusChangedEvent,
      });
      router.route({
        priority: 'normal',
        recipient: 'alice@example.com',
        subject: 'Normal',
        body: 'Normal notification.',
        event: orderCreatedEvent,
      });
      router.route({
        priority: 'low',
        recipient: 'user-1',
        subject: 'Low',
        body: 'Low notification.',
        event: orderCreatedEvent,
      });

      const log = router.getRoutingLog();
      expect(log).toHaveLength(3);
      expect(log[0]?.channel).toBe('sms');
      expect(log[1]?.channel).toBe('email');
      expect(log[2]?.channel).toBe('webhook');
    });

    it('should count routing by channel', () => {
      router.route({
        priority: 'urgent',
        recipient: 'user-1',
        subject: 'A',
        body: 'A',
        event: statusChangedEvent,
      });
      router.route({
        priority: 'urgent',
        recipient: 'user-2',
        subject: 'B',
        body: 'B',
        event: statusChangedEvent,
      });
      router.route({
        priority: 'normal',
        recipient: 'alice@example.com',
        subject: 'C',
        body: 'C',
        event: orderCreatedEvent,
      });

      expect(router.getRoutingCountByChannel('sms')).toBe(2);
      expect(router.getRoutingCountByChannel('email')).toBe(1);
      expect(router.getRoutingCountByChannel('webhook')).toBe(0);
    });

    it('should clear routing log', () => {
      router.route({
        priority: 'urgent',
        recipient: 'user-1',
        subject: 'Test',
        body: 'Test',
        event: statusChangedEvent,
      });

      router.clearRoutingLog();
      expect(router.getRoutingLog()).toHaveLength(0);
    });
  });

  describe('NotificationService integration with priority router', () => {
    it('should route via priority router when sendWithPriority is called', () => {
      emailChannel.setPriorityRouter(router);

      emailChannel.sendWithPriority({
        priority: 'urgent',
        recipient: 'user-1',
        subject: 'Urgent Order',
        body: 'Your order needs attention.',
        event: statusChangedEvent,
      });

      // Should have routed to SMS, not email
      expect(smsChannel.getMessageCount()).toBe(1);
      expect(emailChannel.getNotificationCount()).toBe(0);
    });

    it('should throw if priority router is not configured', () => {
      expect(() => {
        emailChannel.sendWithPriority({
          priority: 'normal',
          recipient: 'alice@example.com',
          subject: 'Test',
          body: 'Test',
          event: orderCreatedEvent,
        });
      }).toThrow('Priority router not configured');
    });

    it('should route normal priority to email via sendWithPriority', () => {
      emailChannel.setPriorityRouter(router);

      emailChannel.sendWithPriority({
        priority: 'normal',
        recipient: 'alice@example.com',
        subject: 'Order Confirmation',
        body: 'Your order is confirmed.',
        event: orderCreatedEvent,
      });

      expect(emailChannel.getNotificationCount()).toBe(1);
      expect(smsChannel.getMessageCount()).toBe(0);
    });

    it('should route low priority to webhook via sendWithPriority', () => {
      emailChannel.setPriorityRouter(router);
      webhookChannel.registerWebhookUrl('order:status-changed', 'https://hooks.example.com/status');

      emailChannel.sendWithPriority({
        priority: 'low',
        recipient: 'user-1',
        subject: 'Status Update',
        body: 'Minor status change.',
        event: statusChangedEvent,
      });

      expect(webhookChannel.getDeliveryCount()).toBe(1);
      expect(emailChannel.getNotificationCount()).toBe(0);
      expect(smsChannel.getMessageCount()).toBe(0);
    });
  });
});

